// Helper function to get movies by genre
export const getMoviesByGenre = (genre) => {
  if (!genre || genre === "all") return moviesData;
  return moviesData.filter(movie => 
    movie.Genre && movie.Genre.toLowerCase().includes(genre.toLowerCase())
  );
};

// Helper function to search movies
export const searchMovies = (query) => {
  if (!query) return moviesData;
  const searchTerm = query.toLowerCase();
  return moviesData.filter(movie => 
    movie.Title.toLowerCase().includes(searchTerm) ||
    (movie.Plot && movie.Plot.toLowerCase().includes(searchTerm)) ||
    (movie.Actors && movie.Actors.toLowerCase().includes(searchTerm)) ||
    (movie.Genre && movie.Genre.toLowerCase().includes(searchTerm))
  );
};

// Helper function to get movie by ID
export const getMovieById = (id) => {
  return moviesData.find(movie => movie.imdbID === id);
};

// Helper function to get movies by type (movie or series)
export const getMoviesByType = (type) => {
  if (!type || type === "all") return moviesData;
  return moviesData.filter(movie => movie.Type === type);
};

// Helper function to get random movies
export const getRandomMovies = (count = 10) => {
  const shuffled = [...moviesData].sort(() => 0.5 - Math.random());
  return shuffled.slice(0, count);
};

// Helper function to get unique genres
export const getAllGenres = () => {
  const genresSet = new Set();
  moviesData.forEach(movie => {
    if (movie.Genre) {
      movie.Genre.split(', ').forEach(genre => {
        genresSet.add(genre.trim());
      });
    }
  });
  return Array.from(genresSet).sort();
};